Sure, here is an example of how to create a crypto token with a 1% tax using Solidity:

```
pragma solidity ^0.8.0;

import "./IERC20.sol";
import "./SafeMath.sol";

contract MyToken is IERC20 {
    using SafeMath for uint256;

    string public name = "My Token";
    string public symbol = "MTK";
    uint256 public decimals = 18;
    uint256 public totalSupply;
    mapping(address => uint256) public balances;
    mapping(address => mapping(address => uint256)) public allowances;

    uint256 private _taxPercent = 1;

    function transfer(address recipient, uint256 amount) public override returns (bool) {
        uint256 taxAmount = amount.mul(_taxPercent).div(100);
        uint256 transferAmount = amount.sub(taxAmount);

        balances[msg.sender] = balances[msg.sender].sub(amount, "transfer amount exceeds balance");
        balances[recipient] = balances[recipient].add(transferAmount);
        balances[address(this)] = balances[address(this)].add(taxAmount);

        emit Transfer(msg.sender, recipient, transferAmount);
        emit Transfer(msg.sender, address(this), taxAmount);

        return true;
    }

    function allowance(address owner, address spender) public view override returns (uint256) {
        return allowances[owner][spender];
    }

    function approve(address spender, uint256 amount) public override returns (bool) {
        allowances[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);

        return true;
    }

    function transferFrom(address sender, address recipient, uint256 amount) public override returns (bool) {
        uint256 taxAmount = amount.mul(_taxPercent).div(100);
        uint256 transferAmount = amount.sub(taxAmount);

        balances[sender] = balances[sender].sub(amount, "transfer amount exceeds balance");
        balances[recipient] = balances[recipient].add(transferAmount);
        balances[address(this)] = balances[address(this)].add(taxAmount);
        allowances[sender][msg.sender] = allowances[sender][msg.sender].sub(amount, "transfer amount exceeds allowance");

        emit Transfer(sender, recipient, transferAmount);
        emit Transfer(sender, address(this), taxAmount);

        return true;
    }

    function increaseAllowance(address spender, uint256 addedValue) public returns (bool) {
        allowances[msg.sender][spender] = allowances[msg.sender][spender].add(addedValue);
        emit Approval(msg.sender, spender, allowances[msg.sender][spender]);

        return true;
    }

    function decreaseAllowance(address spender, uint256 subtractedValue) public returns (bool) {
        uint256 newAllowance = allowances[msg.sender][spender].sub(subtractedValue, "decreased allowance below zero");
        allowances[msg.sender][spender] = newAllowance;
        emit Approval(msg.sender, spender, newAllowance);

        return true;
    }

    function mint(address recipient, uint256 amount) public {
        totalSupply = totalSupply.add(amount);
        balances[recipient] = balances[recipient].add(amount);

        emit Transfer(address(0), recipient, amount);
    }

    function setTaxPercent(uint256 taxPercent) public {
        _taxPercent = taxPercent;
    }
}
```

This code creates a token called "My Token" with the symbol "MTK". The `_taxPercent` variable sets the percentage of the transaction that will be taxed. In this example, it is set to 1%.

The `transfer` function calculates the tax amount and subtracts it from the transfer amount. The `balances` mapping holds the balances of each address, and the `allowances` mapping holds the amounts that each address is allowed to spend on behalf of another address. The `mint` function allows the contract owner to create new tokens and give them to an address.

To use this code, you should copy it into a new file called `MyToken.sol`. Then, you can deploy and test the contract using a blockchain testnet or local development environment.

Here's how you can add a `withdrawTax` function that allows the contract owner to withdraw the accumulated tax balance to their wallet:

1. Declare an address variable `contractOwner` in the contract, to store the address of the owner of the contract.

```
address public contractOwner;
```

2. Set the value of the `contractOwner` variable to the address that deploys the contract in the constructor.

```
constructor() {
        contractOwner = msg.sender;
    }
```

3. Define the `withdrawTax` function that withdraws the tax balance to the contract owner's wallet.

```
function withdrawTax() public {
        require(msg.sender == contractOwner, "Only contract owner can withdraw tax");
        uint256 taxAmount = balances[address(this)];
        balances[address(this)] = 0;
        balances[contractOwner] = balances[contractOwner].add(taxAmount);
        emit Transfer(address(this), contractOwner, taxAmount);
    }
```

4. In the transfer functions, update the line that adds the tax amount to the balance of the contract to use `safeAdd()` instead of `add()`. This ensures that the contract balance cannot overflow and cause an error when the contract owner tries to withdraw the tax.

```
balances[address(this)] = balances[address(this)].safeAdd(taxAmount);
```

